# pyre-strict
"""
Fallback Client Implementation.

This module provides fallback mechanisms when the primary Metamate
service is unavailable, including Stan script execution and Meta AI API.
"""

import asyncio
import logging
from typing import Any

from agent_foundation.common.inferencers.agentic_inferencers.external.metamate.clients.interfaces import (
    FallbackClientInterface,
)


logger: logging.Logger = logging.getLogger(__name__)


class FallbackClient(FallbackClientInterface):
    """
    Fallback client for when Metamate is unavailable.

    This client provides alternative methods for:
    - Research: Stan scripts for external research
    - Q&A: Meta AI API for answering questions

    Example:
        ```python
        fallback = FallbackClient()

        # Execute research fallback
        results = await fallback.execute_research_fallback(
            query="machine learning optimization",
            query_type="external"
        )

        # Execute Q&A fallback
        response = await fallback.execute_qa_fallback(
            question="How do I configure FBLearner?",
            context="Running model training"
        )
        ```
    """

    def __init__(
        self,
        stan_script_path: str | None = None,
        meta_ai_endpoint: str | None = None,
    ) -> None:
        """
        Initialize the fallback client.

        Args:
            stan_script_path: Path to Stan scripts for research fallback.
            meta_ai_endpoint: Endpoint for Meta AI API.
        """
        self._stan_script_path = stan_script_path
        self._meta_ai_endpoint = meta_ai_endpoint
        self._is_available = True

    async def execute_research_fallback(
        self,
        query: str,
        query_type: str,
    ) -> dict[str, Any]:
        """
        Execute research using Stan scripts fallback.

        Args:
            query: Research query.
            query_type: Type of research (external, internal, hybrid).

        Returns:
            Research results from Stan scripts.
        """
        logger.info("Executing research fallback for query: %s", query[:50])

        await asyncio.sleep(0.5)

        return {
            "fallback": True,
            "service": "stan_scripts",
            "query": query,
            "query_type": query_type,
            "results": [
                {
                    "title": f"Fallback Result for: {query[:30]}",
                    "snippet": "This result was generated by the Stan scripts fallback.",
                    "url": "https://fallback.example.com/result",
                    "relevance_score": 0.7,
                }
            ],
            "message": "Results from fallback Stan scripts service",
        }

    async def execute_qa_fallback(
        self,
        question: str,
        context: str | None = None,
    ) -> dict[str, Any]:
        """
        Execute Q&A using Meta AI API fallback.

        Args:
            question: Question to answer.
            context: Optional context for the question.

        Returns:
            Q&A response from Meta AI API.
        """
        logger.info("Executing Q&A fallback for question: %s", question[:50])

        await asyncio.sleep(0.3)

        return {
            "fallback": True,
            "service": "meta_ai_api",
            "question": question,
            "context": context,
            "answer": f"This is a fallback answer to: {question}",
            "confidence": 0.6,
            "citations": [],
            "message": "Answer from Meta AI API fallback service",
        }

    async def health_check(self) -> bool:
        """
        Check if fallback services are available.

        Returns:
            True if at least one fallback service is available.
        """
        return self._is_available

    def set_available(self, is_available: bool) -> None:
        """Set the availability status of the fallback client."""
        self._is_available = is_available
